            int node = q.poll();
            count++;

            // Reduce in-degree of neighbors
            for (int neighbor : adj.get(node)) {
                indegree[neighbor]--;
                if (indegree[neighbor] == 0) {
                    q.add(neighbor);
                }
            }
        }

        // If count != V, cycle exists
        return count != V;
    }
}

