        indegree = [0] * V
        for u in range(V):
            for v in adj[u]:
                indegree[v] += 1

        # Queue for nodes with 0 in-degree
        q = deque()
        for i in range(V):
            if indegree[i] == 0:
                q.append(i)

        # Count visited nodes
        count = 0
        while q:
